const context_dir = '/tmp/jarvis_context';
const session_file = `${context_dir}/session.json`;

const session = {
  userId: $json.userId || 'default',
  sessionId: $json.sessionId || '',
  lastMessage: $json.inputText || '',
  lastResponse: $json.responseText || '',
  lastIntent: $json.intent || '',
  timestamp: new Date().toISOString(),
  version: '4.5.0'
};

try {
  const fs = require('fs');
  if (!fs.existsSync(context_dir)) {
    fs.mkdirSync(context_dir, { recursive: true });
  }
  fs.writeFileSync(session_file, JSON.stringify(session, null, 2));
  $json.memorySaved = true;
  $json.memoryPath = session_file;
} catch (e) {
  $json.memorySaved = false;
  $json.memoryError = e.message;
}

return [{ json: { ...$json, success: true } }];

const facts = [];
try {
  const raw = $json.choices?.[0]?.message?.content || '[]';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(cleaned);
  if (Array.isArray(parsed)) {
    facts.push(...parsed);
  }
} catch (e) {
  // Silent fail - memory extraction is best-effort
}
return [{ json: { ...$json, facts: facts, memoryExtracted: facts.length > 0 } }];
